// 1. Obtenemos el objeto principal que llega de Slack en n8n
const input = $input.all()[0].json;

// 2. Buscamos el texto donde está la información completa.
// En los mensajes modernos de Slack, los detalles están dentro de "blocks"
let textoBruto = "";

if (input.blocks && input.blocks.length > 1 && input.blocks[1].text) {
  // Tomamos el texto del segundo bloque que contiene todos los datos
  textoBruto = input.blocks[1].text.text; 
} else if (input.text) {
  textoBruto = input.text;
}

// 3. Función para extraer el valor después de cada etiqueta
const extraerDato = (etiqueta) => {
  const regex = new RegExp(`${etiqueta}:\\s*([^\n\r]+)`, 'i');
  const coincidencia = textoBruto.match(regex);
  return coincidencia ? coincidencia[1].trim() : "";
};

// 4. Limpiamos los correos (Slack los envía como <mailto:correo|correo>)
const limpiarCorreo = (correoSucio) => {
  if (!correoSucio) return "";
  const match = correoSucio.match(/mailto:([^|>]+)/);
  return match ? match[1] : correoSucio.replace(/[<>*]/g, "").trim();
};

// 5. Extraemos las variables necesarias para hacer las uniones
const aliasExtraido = extraerDato("Alias");
const direccionBase = extraerDato("Dirección");
const apto = extraerDato("Apto/Casa/Otro");

// 6. Construimos el resultado final con el formato exacto solicitado
const resultado = {
  empresa: aliasExtraido ? `AKIENVIO S.A.S/ ${aliasExtraido}` : "AKIENVIO S.A.S",
  id_sucursal: "", // Queda básico/vacío
  nit: "901702784-7",
  contacto: "", // Queda vacío
  telefono: extraerDato("Teléfono"),
  direccion: `${direccionBase} ${apto}`.trim(), // Se juntan con un espacio, sin guiones
  ciudad: extraerDato("Ciudad"),
  email: limpiarCorreo(extraerDato("Usuario")) // Extrae "soporte@akienvio.co" de la línea Usuario
};

// Devolvemos el array de objetos como lo espera n8n
return [resultado];

